"""
{{app_title}} — Flask application entry point.
"""

from flask import Flask, render_template, request, redirect, url_for

app = Flask(__name__)
app.secret_key = "change-me-{{project_name}}"

# ===========================================================================
# In-memory data store (replace with SQLite/Postgres for production)
# ===========================================================================

items: list[dict] = []
next_id = 1


@app.route("/")
def index():
    """Home page — list all items."""
    return render_template("index.html", items=items, title="{{app_title}}")


@app.route("/add", methods=["GET", "POST"])
def add_item():
    """Add a new item."""
    global next_id
    if request.method == "POST":
        items.append({
            "id": next_id,
            "name": request.form["name"],
            "description": request.form.get("description", ""),
        })
        next_id += 1
        return redirect(url_for("index"))
    return render_template("form.html", title="{{app_title}} — Add")


@app.route("/delete/<int:item_id>")
def delete_item(item_id: int):
    """Delete an item by ID."""
    global items
    items = [i for i in items if i["id"] != item_id]
    return redirect(url_for("index"))


if __name__ == "__main__":
    app.run(debug=True)

